export type AlbersParams = { lon0:number; lat0:number; p1:number; p2:number; S:number; offx:number; offy:number };
export const ALBERS_L48: AlbersParams = { lon0:-96, lat0:37.5, p1:29.5, p2:45.5, S:1059.62622, offx:402.8553, offy:271.2885 };
export const ALBERS_AK: AlbersParams = { lon0:-152, lat0:60, p1:55, p2:65, S:370.86918, offx:149.6995, offy:549.9800 };
export const ALBERS_HI: AlbersParams = { lon0:-157, lat0:20, p1:8, p2:18, S:1059.62622, offx:303.1860, offy:568.6650 };
// Project a lon/lat into the shared 960x600 map space for the given state.
export function projectLonLat(abbr: string, lon: number, lat: number): { x: number; y: number } {
  const p = abbr === 'AK' ? ALBERS_AK : abbr === 'HI' ? ALBERS_HI : ALBERS_L48;
  const d2r = Math.PI / 180;
  const lon0 = p.lon0*d2r, lat0 = p.lat0*d2r, p1 = p.p1*d2r, p2 = p.p2*d2r;
  const n = 0.5*(Math.sin(p1)+Math.sin(p2));
  const C = Math.cos(p1)**2 + 2*n*Math.sin(p1);
  const rho0 = Math.sqrt(C - 2*n*Math.sin(lat0))/n;
  const theta = n*(lon*d2r - lon0);
  const rho = Math.sqrt(Math.max(0, C - 2*n*Math.sin(lat*d2r)))/n;
  const rx = rho*Math.sin(theta);
  const ry = -(rho0 - rho*Math.cos(theta));
  return { x: rx*p.S + p.offx, y: ry*p.S + p.offy };
}
